import React, { useState } from "react";
import axios from "axios";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Tooltip,
  Legend,
  Filler,
  TimeScale,
  Title,
} from "chart.js";

import "chartjs-adapter-date-fns";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Tooltip,
  Legend,
  Filler,
  TimeScale,
  Title
);

const formatCurrency = (value) => {
  if (value == null) return "N/A";
  return `₹${Number(value).toLocaleString("en-IN")}`;
};

const formatNumber = (value, decimals = 2) => {
  if (value == null) return "N/A";
  return Number(value).toFixed(decimals);
};

const IndianStockDetails = () => {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const fetchData = async () => {
    setError("");
    setLoading(true);
    setData(null);

    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch stock data.");
    } finally {
      setLoading(false);
    }
  };

  const renderPriceLineChart = (quotes) => {
    if (!quotes?.length) return <p>No chart data available.</p>;

    const labels = quotes.map((q) => new Date(q.date));
    const closePrices = quotes.map((q) => q.close);

    const chartData = {
      labels,
      datasets: [
        {
          label: "Closing Price",
          data: closePrices,
          borderColor: "#007bff",
          backgroundColor: (context) => {
            const chart = context.chart;
            const { ctx, chartArea } = chart;
            if (!chartArea) return null;
            const gradient = ctx.createLinearGradient(
              0,
              chartArea.top,
              0,
              chartArea.bottom
            );
            gradient.addColorStop(0, "rgba(0,123,255,0.4)");
            gradient.addColorStop(1, "rgba(0,123,255,0.05)");
            return gradient;
          },
          fill: true,
          tension: 0.4,
          pointRadius: 0,
        },
      ],
    };

    const options = {
      responsive: true,
      plugins: {
        legend: {
          display: false,
        },
        tooltip: {
          callbacks: {
            label: (ctx) => `₹${ctx.parsed.y.toFixed(2)}`,
          },
        },
        title: {
          display: true,
          text: "Price Trend",
          color: "#333",
          font: {
            size: 18,
            weight: "bold",
          },
        },
      },
      scales: {
        x: {
          type: "time",
          time: {
            unit: "month",
            tooltipFormat: "MMM d, yyyy",
          },
          grid: {
            display: false,
          },
        },
        y: {
          ticks: {
            callback: (val) => `₹${val}`,
          },
        },
      },
    };

    return <Line data={chartData} options={options} />;
  };

  const metricList = [
    { label: "EPS", key: "eps" },
    { label: "ROE (%)", key: "roe" },
    { label: "Book Value", key: "bookValue", currency: true },
    { label: "Face Value", key: "faceValue", currency: true },
    { label: "PE Ratio", key: "peRatio" },
    { label: "Dividend Yield (%)", key: "dividendYield" },
    { label: "ROCE (%)", key: "roce" },
    { label: "Market Cap", key: "marketCap", currency: true },
    { label: "52 Week High", key: "fiftyTwoWeekHigh", currency: true },
    { label: "52 Week Low", key: "fiftyTwoWeekLow", currency: true },
  ];

  const renderMetricCard = (label, value, isCurrency = false) => (
    <div
      key={label}
      style={{
        flex: "1 1 200px",
        margin: "10px",
        padding: "15px",
        background: "#f8f9fa",
        borderRadius: "8px",
        boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
      }}
    >
      <div style={{ fontSize: "14px", color: "#666" }}>{label}</div>
      <div
        style={{
          fontSize: "18px",
          fontWeight: "bold",
          color: "#007bff",
          marginTop: "5px",
        }}
      >
        {isCurrency ? formatCurrency(value) : formatNumber(value)}
      </div>
    </div>
  );

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h2>📈 Indian Stock Details</h2>

      <div style={{ marginBottom: "20px" }}>
        <input
          type="text"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value)}
          placeholder="Enter Symbol (e.g. TCS.NS)"
          style={{
            padding: "10px",
            width: "250px",
            marginRight: "10px",
            borderRadius: "4px",
            border: "1px solid #ccc",
          }}
        />
        <button
          onClick={fetchData}
          disabled={loading}
          style={{
            padding: "10px 20px",
            backgroundColor: "#007bff",
            color: "#fff",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
          }}
        >
          {loading ? "Loading..." : "Get Details"}
        </button>
      </div>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <>
          <h3>
            {data.name} ({data.symbol})
          </h3>
          <h1
            style={{
              color: data.change > 0 ? "green" : "red",
              marginTop: "10px",
            }}
          >
            ₹{formatNumber(data.price)} | Change: {formatNumber(data.change)} (
            {formatNumber(data.percentChange)}%)
          </h1>

          {/* Render metric cards */}
          <div
            style={{
              display: "flex",
              flexWrap: "wrap",
              justifyContent: "flex-start",
              marginTop: "20px",
            }}
          >
            {metricList.map((metric) =>
              renderMetricCard(
                metric.label,
                data[metric.key],
                metric.currency
              )
            )}
          </div>

          {/* Price Line Chart */}
          <div style={{ marginTop: "40px" }}>
            {renderPriceLineChart(data?.historical?.quotes)}
          </div>
        </>
      )}
    </div>
  );
};

export default IndianStockDetails;
